29.6.2 Agent Definitions
# src/agents/researcher.py

class ResearcherAgent(BaseAgent):
    def __init__(self, model_client, tools):
        super().__init__(model_client)
        self.tools = tools

    def execute(self, task):
        """Execute research task."""
        # Understand research question
        research_plan = self.plan_research(task['question'])

        # Conduct research
        findings = []
        for step in research_plan:
            result = self.execute_research_step(step)
            findings.append(result)

        # Synthesize findings
        synthesis = self.synthesize_findings(findings)

        return synthesis

    def plan_research(self, question):
        """Plan research approach."""
        prompt = f"""
Plan research for this question:
{question}

Available tools: {self.tool_names}

Create a step-by-step research plan.
"""
        return self.think(prompt)

    def execute_research_step(self, step):
        """Execute a single research step."""
        tool_name = step['tool']
        tool = self.tools[tool_name]

        return tool.execute(step['parameters'])

    def synthesize_findings(self, findings):
        """Synthesize research findings."""
        prompt = f"""
Synthesize these research findings:
{findings}

Provide a comprehensive summary.
"""
        return self.think(prompt)
# src/agents/analyst.py

class AnalystAgent(BaseAgent):
    def __init__(self, model_client):
        super().__init__(model_client)

    def execute(self, task):
        """Analyze research findings."""
        findings = task['findings']

        # Identify key insights
        insights = self.extract_insights(findings)

        # Identify patterns
        patterns = self.identify_patterns(findings)

        # Draw conclusions
        conclusions = self.draw_conclusions(insights, patterns)

        return {
            'insights': insights,
            'patterns': patterns,
            'conclusions': conclusions
        }

    def extract_insights(self, findings):
        """Extract key insights from findings."""
        prompt = f"""
Extract key insights from these findings:
{findings}

List the most important insights.
"""
        return self.think(prompt)

    def identify_patterns(self, findings):
        """Identify patterns in findings."""
        prompt = f"""
Identify patterns in these findings:
{findings}

What patterns emerge?
"""
        return self.think(prompt)

    def draw_conclusions(self, insights, patterns):
        """Draw conclusions from insights and patterns."""
        prompt = f"""
Based on these insights and patterns:
Insights: {insights}
Patterns: {patterns}

Draw conclusions.
"""
        return self.think(prompt)
# src/agents/writer.py

class WriterAgent(BaseAgent):
    def __init__(self, model_client):
        super().__init__(model_client)

    def execute(self, task):
        """Write report based on analysis."""
        analysis = task['analysis']
        topic = task['topic']

        # Create outline
        outline = self.create_outline(topic, analysis)

        # Write sections
        report = ""
        for section in outline:
            content = self.write_section(section, analysis)
            report += f"\n\n{section}\n{content}"

        return report

    def create_outline(self, topic, analysis):
        """Create report outline."""
        prompt = f"""
Create an outline for a report on:
{topic}

Based on this analysis:
{analysis}

Provide section titles and brief descriptions.
"""
        return self.think(prompt)

    def write_section(self, section, analysis):
        """Write a section of the report."""
        prompt = f"""
Write this section: {section}

Based on this analysis:
{analysis}

Provide well-structured content.
"""
        return self.think(prompt)
# src/agents/critic.py

class CriticAgent(BaseAgent):
    def __init__(self, model_client):
        super().__init__(model_client)

    def execute(self, task):
        """Critique and provide feedback."""
        report = task['report']

        # Identify issues
        issues = self.identify_issues(report)

        # Suggest improvements
        suggestions = self.suggest_improvements(report, issues)

        # Rate quality
        rating = self.rate_quality(report)

        return {
            'issues': issues,
            'suggestions': suggestions,
            'rating': rating
        }

    def identify_issues(self, report):
        """Identify issues in report."""
        prompt = f"""
Identify issues in this report:
{report}

Check for:
- Factual errors
- Logical inconsistencies
- Missing information
- Clarity problems

List the issues found.
"""
        return self.think(prompt)

    def suggest_improvements(self, report, issues):
        """Suggest improvements for the report."""
        prompt = f"""
Suggest improvements for this report:
{report}

Issues identified:
{issues}

Provide specific suggestions.
"""
        return self.think(prompt)

    def rate_quality(self, report):
        """Rate the quality of the report."""
        prompt = f"""
Rate this report on a scale of 1-10 for:
- Content quality
- Clarity
- Structure

Report:
{report}

Provide a single overall rating (1-10).
"""
        response = self.think(prompt)
        try:
            return float(response.strip())
        except:
            return 5.0


