class SemanticCache:
    def __init__(self, similarity_threshold=0.95, embedding_model=None):
        self.cache = []
        self.similarity_threshold = similarity_threshold
        self.embedding_model = embedding_model

    def find_similar(self, prompt: str) -&gt; Optional[str]:
        """Find semantically similar cached prompt."""
        if not self.embedding_model:
            return None

        prompt_embedding = self.embedding_model.embed_text(prompt)

        for cached in self.cache:
            similarity = self.cosine_similarity(
                prompt_embedding,
                cached['embedding']
            )

            if similarity &gt;= self.similarity_threshold:
                return cached['response']

        return None

    def cosine_similarity(self, a, b):
        """Calculate cosine similarity."""
        import numpy as np
        return np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b))

    def add(self, prompt: str, response: str):
        """Add prompt to cache."""
        if self.embedding_model:
            embedding = self.embedding_model.embed_text(prompt)
        else:
            embedding = None

        self.cache.append({
            'prompt': prompt,
            'response': response,
            'embedding': embedding
        })


